const rand=(min,max)=>Math.random()*(max-min)+min;
function pick(arr){return arr[Math.floor(Math.random()*arr.length)]}
function pos(){let x=rand(2,84),y=rand(5,82),g=0;while(x>22&&x<72&&y>24&&y<72&&g<12){x=rand(2,84);y=rand(5,82);g++}return{x,y}}
function addInfectedSticker(){if(document.hidden||!stageForEffects)return;const s=pick(stickers);const node=document.createElement('div');node.className=`pop-item pop-sticker ${s.cls}`;const p=pos();node.style.left=`${p.x}%`;node.style.top=`${p.y}%`;node.style.width=`${rand(42,94)}px`;node.style.aspectRatio=`${s.w}/${s.h}`;node.style.setProperty('--dx',`${rand(-24,24)}px`);node.style.setProperty('--dy',`${rand(-18,18)}px`);node.style.setProperty('--rot',`${rand(-18,18)}deg`);node.style.animationDuration=`${rand(3.2,5.8)}s`;node.innerHTML=s.html;stickerLayer.appendChild(node);while(stickerLayer.children.length>18){stickerLayer.firstChild.remove()}setTimeout(()=>node.remove(),6200)}
for(let i=0;i<8;i++)setTimeout(addInfectedSticker,180+i*130);
setInterval(addInfectedSticker,680);
